#include <iostream>

using namespace std;

int main()
{
    for (int i = 1; i <= 5; i++)
    {
        if (i == 3)
        {
            continue;
        }
        cout << i << endl;
    }

    return 0;
}

int i = 1;

while (i <= 5)
{
    if (i == 3)
    {
        continue; // DANGER: skips i++ below, i stays 3 forever
    }
    cout << i << endl;
    i++;
}

#include <iostream>

using namespace std;

int main()
{
    for (int i = 1; i <= 10; i++)
    {
        if (i % 2 != 0)
        {
            continue; // skip odd numbers
        }
        cout << i << endl;
    }

    return 0;
}

